code.C:
#include <stdio.h>
#include <stdlib.h>

typedef struct {
    char name[51];
    char author[51];
    float price;
} Book;

int main() {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    Book *books = (Book *)malloc(n * sizeof(Book));
    for (int i = 0; i < n; ++i) {
        scanf("%s %s %f", books[i].name, books[i].author, &books[i].price);
    }
    for (int i = 0; i < n; ++i) {
        printf("Book Name: %s\n", books[i].name);
        printf("Author: %s\n", books[i].author);
        printf("Price: %.2f\n", books[i].price);
        if (i != n - 1) printf("\n");
    }
    free(books);
    return 0;
}

