code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static class Book {
        String name;
        String author;
        float price;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int n = Integer.parseInt(br.readLine().trim());
        Book[] books = new Book[n];
        for (int i = 0; i < n; ++i) {
            st = new StringTokenizer(br.readLine());
            Book b = new Book();
            b.name = st.nextToken();
            b.author = st.nextToken();
            b.price = Float.parseFloat(st.nextToken());
            books[i] = b;
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; ++i) {
            sb.append("Book Name: ").append(books[i].name).append('\n');
            sb.append("Author: ").append(books[i].author).append('\n');
            sb.append(String.format("Price: %.2f", books[i].price)).append('\n');
            if (i != n - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

